import { describe, expect, it } from 'vitest';
import { runXoPhase2VerificationMatrix } from '../../src/verification/xo_phase2_matrix';

describe('runXoPhase2VerificationMatrix', () => {
  it('requires all supervised tutor invariants for a passing exit score', () => {
    const result = runXoPhase2VerificationMatrix({
      invariants: {
        oneChildScope: true,
        lessonBoundTutoring: true,
        guardianAuthority: true,
        disclosureBoundary: true,
        escalationTraceability: true
      }
    });
    expect(result.passed).toBe(true);
    expect(result.score).toBeGreaterThanOrEqual(0.95);
  });
});

target_file_skeleton:
export interface XoPhase2VerificationInput {
  invariants: {
    oneChildScope: boolean;
    lessonBoundTutoring: boolean;
    guardianAuthority: boolean;
    disclosureBoundary: boolean;
    escalationTraceability: boolean;
  };
}

export function runXoPhase2VerificationMatrix(input: XoPhase2VerificationInput) {
  const passed = Object.values(input.invariants).every(Boolean);
  return {
    passed,
    score: passed ? 1 : 0,
    evidence: input.invariants
  };
}
